// Simple cylinder with diameter 30mm and height 50mm
$fn = 64; // High quality rendering

// Main cylinder parameters
diameter = 30; // Cylinder diameter in mm
radius = diameter / 2; // Calculate radius from diameter
height = 50; // Cylinder height in mm

// Center the cylinder at origin
translate([0, 0, -height/2]) {
    cylinder(h = height, r = radius, center = false);
}...
